  width: $size-grid-icon;
  height: $size-grid-icon;
  border-radius: $radius-lg;
}

.grid-item__title {
  font-size: $font-sm;
  color: $color-text-primary;
  text-align: center;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 100%;
}

.grid-item__subtitle {
